211→const TASK_PROMPT = `
212→1 - Understand and write your understanding of every single and
213→each WORKFLOW AND CRITICAL statement.
214→2 - Understand and write your understanding of the work in progress
215→  described in progress.txt and compared with the actual files.
216→
217→WORKFLOW:
218→0. Understand Project
219→1. Read ./.claude/progress.txt and identify the most important pending task;
220→   - Specific task prioritization is indicated/tagged/prefixed with '[P'+number+']'
221→   - Tasks tagged with '[P0]' must be done before anything else.
222→   - Tasks tagged with P bigger than 999 (e.g. '[P1000]'), are low-priority
223→   tasks, they should be done when possible, but they must be done
224→   (they are not ignorable); If the task takes longer and there are other
225→   non-low-priority tasks, document progress and revert the status to "- [ ]".
226→
227→2. If NO pending tasks exist, plan next improvements, add tasks and stop
228→3. If there are tasks, mark it as IN_PROGRESS and then sequentially run:
229→   - Evaluate scope: if the task involves more than ~3 files or multiple concerns,
230→      break it into smaller sub-tasks in progress.txt BEFORE starting. Each sub-task
231→      must be completable in a single iteration (small, atomic, committable change).
232→   - Execute task
233→   - Run 'bun run check' and fix found issues.
234→   - Launch 1 review agents to deeply review the work, giving
235→      the entire context of the task, simulating pull request.
236→   - Review output and consider improvements
237→   - Implement corrections if needed
238→   - Update progress.txt marking task as completed
239→   - Commit task changes (not include unrelated code)
240→   - Output status block (see below)
241→   - Stop
242→
243→CRITICAL:
244→- ALL tasks and instructions are deliberate.
245→- No task is optional.
246→- If more work is necessary, add a new task to the file, set "exit": false, and Stop
247→- Never remove tasks, unless to update status;
248→- Never include workarounds and add tasks to fix all you found ('as any' for example is a workaround)
249→- No task should be submitted as "look reasonable."
250→- Every task must be delivered with professional quality, without any makeshift solutions.
251→- For tasks with visual parts, full visual and interaction tests with Playwright MCP are required.
252→- Never consider any mistake or error to be expected or acceptable.- Never consider any mistake or error to be expected or acceptable.
253→- Never trust project comments or documentation without confirming on actual
254→code.
255→
256→--------------------------------------------------------------------------------
257→
258→OUTPUT STATUS (REQUIRED at end of EVERY response):
259→You MUST output this exact format at the END of your response:
260→
261→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
262→
263→Examples:
264→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
265→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
266→
267→`;
268→
269→interface ContentBlock {
270→  type: 'text' | 'tool_use' | 'tool_result';
271→  text?: string;
272→  name?: string;
273→  input?: unknown;
274→  content?:
275→    | string
276→    | Array<{
277→        type: string;
278→        text?: string;
279→      }>;
280→}
281→
282→interface StreamMessage {
283→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
284→  subtype?: string;
285→  role?: 'assistant' | 'user';
286→  event?: {
287→    type: string;
288→    delta?: {
289→      type: string;
290→      text?: string;
291→    };
292→  };
293→  result?: string;
294→  message?: {
295→    role?: string;
296→    content?: ContentBlock[];
297→  };
298→  content?: ContentBlock[];
299→}
300→
301→function parseRalphStatus(output: string): RalphStatus | null {
302→  const marker = output.lastIndexOf('RALPH_STATUS:');
303→  if (marker === -1) return null;
304→
305→  const jsonStart = output.indexOf('{', marker);
306→  if (jsonStart === -1) return null;
307→
308→  let depth = 0;
309→  for (let i = jsonStart; i < output.length; i++) {
310→    if (output[i] === '{') depth++;
311→    if (output[i] === '}') depth--;
312→    if (depth === 0) {
313→      try {
314→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
315→        if (typeof parsed.exit === 'boolean') {
316→          return parsed as RalphStatus;
317→        }
318→      } catch {}
319→      return null;
320→    }
321→  }
322→  return null;
323→}
324→
325→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
326→
327→function killCurrentProc(): void {
328→  if (!currentProc) return;
329→  try {
330→    currentProc.kill();
331→  } catch {}
332→}
333→
334→async function checkDependencies(): Promise<void> {
335→  const result = await Bun.$`which claude`.quiet().nothrow();
336→  if (result.exitCode !== 0) {
337→    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
338→    process.exit(1);
339→  }
340→
341→  if (!(await Bun.file(CONFIG.progressFile).exists())) {
342→    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
343→    process.exit(1);
344→  }
345→}
346→
347→async function runIteration(): Promise<IterationResult> {
348→  syslog('Executing Claude Code...');
349→
350→  const proc = Bun.spawn(
351→    [
352→      'claude',
353→      '-p',
354→      TASK_PROMPT,
355→      '--verbose',
356→      '--debug',
357→      '--dangerously-skip-permissions',
358→      '--output-format',
359→      'stream-json',
360→      '--include-partial-messages',
361→      '--model=opus',
362→    ],
363→    {
364→      cwd: process.cwd(),
365→      env: process.env,
366→      stdout: 'pipe',
367→      stderr: 'inherit',
368→    },
369→  );
370→
371→  currentProc = proc;
372→
373→  const chunks: string[] = [];
374→  let timedOut = false;
375→  const decoder = new TextDecoder();
376→  let buffer = '';
377→  let blockHasContent = false;
378→
379→  const timeoutId = setTimeout(() => {
380→    timedOut = true;
381→    syslog('Iteration timeout reached. Killing process...', 'yellow');
382→    killCurrentProc();
383→  }, CONFIG.iterationTimeout);
384→
385→  const reader = proc.stdout.getReader();
386→
387→  try {
388→    while (true) {
389→      const { done, value } = await reader.read();
390→      if (done) break;
391→
392→      buffer += decoder.decode(value, { stream: true });
393→
394→      const lines = buffer.split('\n');
395→      buffer = lines.pop() || '';
396→
397→      for (const line of lines) {
398→        if (!line.trim()) continue;
399→
400→        let msg: StreamMessage;
401→        try {
402→          msg = JSON.parse(line);
403→        } catch {
404→          continue;
405→        }
406→
407→        if (msg.type === 'stream_event') {
408→          const evt = msg.event;
409→          if (!evt) continue;
410→
411→          if (evt.type === 'content_block_start') {
412→            blockHasContent = false;
413→          } else if (evt.type === 'content_block_delta') {
414→            const text = evt.delta?.text;
415→            if (text) {
416→              print(text);
417→              chunks.push(text);
418→              blockHasContent = true;
419→            }
420→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
421→            print('\n');
422→            chunks.push('\n');
423→            blockHasContent = false;
424→          }
425→          continue;
426→        }
427→
428→        if (msg.type === 'assistant' || msg.type === 'message') {
429→          const blocks = msg.message?.content ?? msg.content;
430→          if (!Array.isArray(blocks)) continue;
431→
432→          for (const block of blocks) {
433→            if (block.type === 'text' && block.text && chunks.length === 0) {
434→              print(block.text);
435→              chunks.push(block.text);
436→              print('\n');
437→              chunks.push('\n');
438→            }
439→          }
440→          continue;
441→        }
442→
443→        if (msg.type === 'user') {
444→          const blocks = msg.message?.content ?? msg.content;
445→          if (!Array.isArray(blocks)) continue;
446→
447→          for (const block of blocks) {
448→            if (block.type === 'tool_result' && block.content) {
449→              const rawContent =
450→                typeof block.content === 'string'
451→                  ? block.content
452→                  : block.content
453→                      .map(c => c.text ?? '')
454→                      .filter(Boolean)
455→                      .join('\n');
456→
457→              if (!rawContent) continue;
458→
459→              let trimmed = rawContent.trim().slice(0, 320);
460→
461→              const toolResult =
462→                trimmed && trimmed !== rawContent
463→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
464→                  : rawContent;
465→
466→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
467→              chunks.push('\n', rawContent, '\n');
468→            }
469→          }
470→          continue;
471→        }
472→
473→        if (msg.type === 'result' && msg.result) {
474→          if (chunks.length === 0) {
475→            chunks.push(msg.result);
476→          }
477→        }
478→      }
479→    }
480→
481→    if (buffer.trim()) {
482→      try {
483→        const msg: StreamMessage = JSON.parse(buffer);
484→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
485→          chunks.push(msg.result);
486→        }
487→      } catch {}
488→    }
489→  } finally {
490→    clearTimeout(timeoutId);
491→    reader.releaseLock();
492→    currentProc = null;
493→    logBuffer.flush();
494→  }
495→
496→  const output = chunks.join('');
497→
498→  if (timedOut) {
499→    return {
500→      output,
501→      exitCode: 124,
502→      timedOut: true,
503→    };
504→  }
505→
506→  const exitCode = await proc.exited;
507→  println();
508→  return {
509→    output,
510→    exitCode,
511→    timedOut: false,
512→  };
513→}
514→
515→function printHeader(): void {
516→  println();
517→  println('==========================================', 'blue');
518→  println('   Ralph Loop - Bun.js Edition', 'blue');
519→  println('==========================================', 'blue');
520→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
521→  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
522→  println(
523→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
524→  );
525→  println(
526→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
527→  );
528→  println();
529→}
530→
531→async function main(): Promise<void> {
532→  let cleanupCalled = false;
533→
534→  const cleanup = (signal: string) => {
535→    if (cleanupCalled) return;
536→    cleanupCalled = true;
537→    try {
538→      hooks.cleanup.dispatch(signal, undefined);
539→    } catch (err) {
540→      console.error(`[cleanup hook error] ${err}`);
541→    }
542→    println();
543→    syslog(`Interrupted by ${signal}. Cleaning up...`);
544→    killCurrentProc();
545→    logBuffer.dispose();
546→    process.exit(signal === 'SIGINT' ? 130 : 143);
547→  };
548→
549→  process.on('SIGINT', () => cleanup('SIGINT'));
550→  process.on('SIGTERM', () => cleanup('SIGTERM'));
551→
552→  await checkDependencies();
553→
554→  printHeader();
555→  syslog('Starting automated task loop...');
556→
557→  await dispatchSafe(hooks.loopStart, 'loopStart', CONFIG, undefined);
558→
559→  let consecutiveFailures = 0;
560→  let iteration = 0;
561→  const BACKOFF_BASE_MS = 60_000;
562→  const BACKOFF_MAX_MS = 5 * 60 * 60_000;
563→
564→  while (iteration < CONFIG.maxIterations) {
565→    const attemptNum = iteration + 1;
566→    logBuffer.startNewFile(logFilePath(`iter-${attemptNum}`));
567→
568→    const iterCtx: IterationContext = {
569→      iteration: attemptNum,
570→      maxIterations: CONFIG.maxIterations,
571→      logPath: logBuffer.currentPath(),
572→    };
573→
574→    println();
575→    println('==========================================', 'green');
576→    syslog(`Iteration #${attemptNum} / ${CONFIG.maxIterations}`, 'green');
577→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
578→    println('==========================================', 'green');
579→    println();
580→
581→    await dispatchSafe(
582→      hooks.iterationStart,
583→      'iterationStart',
584→      iterCtx,
585→      undefined,
586→    );
587→
588→    const result = await runIteration();
589→    const { output, exitCode, timedOut } = result;
590→
591→    if (exitCode === 0) {
592→      syslog('Claude Code completed successfully', 'green');
593→      consecutiveFailures = 0;
594→      await dispatchSafe(
595→        hooks.iterationSuccess,
596→        'iterationSuccess',
597→        result,
598→        iterCtx,
599→      );
600→    } else if (timedOut) {
601→      syslog(
602→        'Iteration timed out — progress may persist in progress.txt',
603→        'yellow',
604→      );
605→      consecutiveFailures = 0;
606→      await dispatchSafe(
607→        hooks.iterationTimeout,
608→        'iterationTimeout',
609→        result,
610→        iterCtx,
611→      );
612→    } else {
613→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
614→      consecutiveFailures++;
615→
616→      const failCtx: FailureContext = {
617→        ...iterCtx,
618→        exitCode,
619→        consecutiveFailures,
620→      };
621→      await dispatchSafe(
622→        hooks.iterationFailure,
623→        'iterationFailure',
624→        result,
625→        failCtx,
626→      );
627→
628→      const backoffMs = Math.min(
629→        BACKOFF_BASE_MS * Math.pow(2, consecutiveFailures - 1),
630→        BACKOFF_MAX_MS,
631→      );
632→      const backoffMin = (backoffMs / 60_000).toFixed(1);
633→
634→      const backoffCtx: BackoffContext = { ...failCtx, backoffMs };
635→      const skipBackoff = await dispatchSafe(
636→        hooks.shouldSkipBackoff,
637→        'shouldSkipBackoff',
638→        false,
639→        backoffCtx,
640→      );
641→
642→      if (skipBackoff === true) {
643→        syslog('Backoff skipped by hook', 'yellow');
644→      } else {
645→        println();
646→        println('==========================================', 'yellow');
647→        syslog(
648→          `${consecutiveFailures} consecutive failure(s) — retrying in ${backoffMin}min`,
649→          'yellow',
650→        );
651→        println('==========================================', 'yellow');
652→        await Bun.sleep(backoffCtx.backoffMs);
653→      }
654→      continue;
655→    }
656→
657→    iteration++;
658→
659→    const rawStatus = parseRalphStatus(output);
660→    const status = await dispatchSafe(
661→      hooks.resolveStatus,
662→      'resolveStatus',
663→      rawStatus,
664→      output,
665→    );
666→    const taskSlug = status
667→      ? slugify(status.task)
668→      : timedOut
669→        ? 'timeout'
670→        : 'no-status';
671→    logBuffer.renameFile(logFilePath(taskSlug));
672→
673→    if (status?.exit) {
674→      await dispatchSafe(
675→        hooks.allTasksComplete,
676→        'allTasksComplete',
677→        status,
678→        iteration,
679→      );
680→      println();
681→      println('==========================================', 'green');
682→      syslog('ALL TASKS COMPLETED!', 'green');
683→      syslog(`Final task:      ${status.task}`, 'green');
684→      syslog(`Remaining:       ${status.remaining}`, 'green');
685→      syslog(`Total iterations: ${iteration}`, 'green');
686→      println('==========================================', 'green');
687→      logBuffer.dispose();
688→      process.exit(0);
689→    }
690→
691→    if (status) {
692→      await dispatchSafe(
693→        hooks.taskComplete,
694→        'taskComplete',
695→        status,
696→        iterCtx,
697→      );
698→      syslog(
699→        `Task done: "${status.task}" — ${status.remaining} remaining`,
700→        'blue',
701→      );
702→    } else if (!timedOut && exitCode === 0) {
703→      syslog(
704→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
705→        'yellow',
706→      );
707→    }
708→
709→    if (iteration < CONFIG.maxIterations) {
710→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
711→      println();
